-- Webhook logging and payment transaction tables for GDPR compliance and monitoring\n\n-- Payment transactions (idempotent, immutable audit log)\nCREATE TABLE IF NOT EXISTS \"payment_transactions\" (\n  \"id\" TEXT NOT NULL PRIMARY KEY,\n  \"external_transaction_id\" TEXT NOT NULL UNIQUE,\n  \"external_customer_id\" TEXT NOT NULL,\n  \"provider\" TEXT NOT NULL, -- 'stripe' | 'paypal' | 'chapa'\n  \"amount\" DECIMAL(18, 2) NOT NULL,\n  \"currency\" VARCHAR(3) NOT NULL,\n  \"status\" VARCHAR(20) NOT NULL, -- 'pending' | 'completed' | 'failed' | 'refunded'\n  \"metadata\" JSONB,\n  \"schedule_delete_at\" TIMESTAMP, -- GDPR retention\n  \"deleted_at\" TIMESTAMP, -- Soft delete for compliance\n  \"created_at\" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  \"updated_at\" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX \"idx_payment_transactions_external_customer_id\" ON \"payment_transactions\"(\"external_customer_id\");\nCREATE INDEX \"idx_payment_transactions_provider\" ON \"payment_transactions\"(\"provider\");\nCREATE INDEX \"idx_payment_transactions_status\" ON \"payment_transactions\"(\"status\");\nCREATE INDEX \"idx_payment_transactions_created_at\" ON \"payment_transactions\"(\"created_at\");\n\n-- Webhook logs (monitoring and retry tracking)\nCREATE TABLE IF NOT EXISTS \"webhook_logs\" (\n  \"id\" TEXT NOT NULL PRIMARY KEY,\n  \"idempotency_key\" TEXT NOT NULL UNIQUE,\n  \"provider\" TEXT NOT NULL, -- 'stripe' | 'paypal' | 'chapa'\n  \"event_type\" VARCHAR(100) NOT NULL,\n  \"external_id\" TEXT NOT NULL,\n  \"status_code\" INTEGER,\n  \"is_verified\" BOOLEAN NOT NULL DEFAULT FALSE,\n  \"ip_address\" VARCHAR(50),\n  \"user_agent\" TEXT,\n  \"request_body\" JSONB NOT NULL,\n  \"response_body\" JSONB,\n  \"error\" TEXT,\n  \"retry_count\" INTEGER NOT NULL DEFAULT 0,\n  \"retry_until\" TIMESTAMP, -- Next retry scheduled at\n  \"processed_at\" TIMESTAMP, -- When successfully processed\n  \"created_at\" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  \"updated_at\" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX \"idx_webhook_logs_provider\" ON \"webhook_logs\"(\"provider\");\nCREATE INDEX \"idx_webhook_logs_event_type\" ON \"webhook_logs\"(\"event_type\");\nCREATE INDEX \"idx_webhook_logs_processed_at\" ON \"webhook_logs\"(\"processed_at\");\nCREATE INDEX \"idx_webhook_logs_retry_until\" ON \"webhook_logs\"(\"retry_until\") WHERE \"retry_until\" IS NOT NULL;\nCREATE INDEX \"idx_webhook_logs_is_verified\" ON \"webhook_logs\"(\"is_verified\");\n\n-- GDPR consent tracking\nCREATE TABLE IF NOT EXISTS \"gdpr_consents\" (\n  \"id\" TEXT NOT NULL PRIMARY KEY,\n  \"user_id\" TEXT NOT NULL REFERENCES \"users\"(\"id\") ON DELETE CASCADE,\n  \"purpose\" VARCHAR(100) NOT NULL, -- 'payment' | 'marketing' | 'analytics'\n  \"version\" VARCHAR(20) NOT NULL, -- Consent version for audit\n  \"ip_address\" VARCHAR(50),\n  \"user_agent\" TEXT,\n  \"consented_at\" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  \"created_at\" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX \"idx_gdpr_consents_user_id\" ON \"gdpr_consents\"(\"user_id\");\nCREATE INDEX \"idx_gdpr_consents_purpose\" ON \"gdpr_consents\"(\"purpose\");\n\n-- Disputes for chargeback/payment issues\nCREATE TABLE IF NOT EXISTS \"disputes\" (\n  \"id\" TEXT NOT NULL PRIMARY KEY,\n  \"reason\" TEXT NOT NULL,\n  \"status\" VARCHAR(20) NOT NULL DEFAULT 'open', -- 'open' | 'resolved' | 'won' | 'lost'\n  \"amount\" DECIMAL(18, 2) NOT NULL,\n  \"currency\" VARCHAR(3) NOT NULL,\n  \"external_id\" TEXT,\n  \"provider\" TEXT,\n  \"metadata\" JSONB,\n  \"resolved_at\" TIMESTAMP,\n  \"resolution_notes\" TEXT,\n  \"created_at\" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  \"updated_at\" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX \"idx_disputes_status\" ON \"disputes\"(\"status\");\nCREATE INDEX \"idx_disputes_provider\" ON \"disputes\"(\"provider\");\nCREATE INDEX \"idx_disputes_created_at\" ON \"disputes\"(\"created_at\");\n\n-- Alter existing user table to add GDPR and payment provider fields\nALTER TABLE \"users\" ADD COLUMN IF NOT EXISTS \"gdpr_consent_date\" TIMESTAMP;\nALTER TABLE \"users\" ADD COLUMN IF NOT EXISTS \"gdpr_consent_revoked\" BOOLEAN DEFAULT FALSE;\nALTER TABLE \"users\" ADD COLUMN IF NOT EXISTS \"gdpr_consent_revoked_at\" TIMESTAMP;\nALTER TABLE \"users\" ADD COLUMN IF NOT EXISTS \"external_customer_id\" TEXT;\nALTER TABLE \"users\" ADD COLUMN IF NOT EXISTS \"subscription_status\" VARCHAR(50); -- 'active' | 'cancelled' | 'suspended'\nALTER TABLE \"users\" ADD COLUMN IF NOT EXISTS \"subscription_provider\" VARCHAR(50); -- 'stripe' | 'paypal' | 'chapa'\nALTER TABLE \"users\" ADD COLUMN IF NOT EXISTS \"external_subscription_id\" TEXT;\n\n-- Alter wallet_transactions to support multiple payment providers\nALTER TABLE \"wallet_transactions\" ADD COLUMN IF NOT EXISTS \"external_transaction_id\" TEXT;\nALTER TABLE \"wallet_transactions\" ADD COLUMN IF NOT EXISTS \"provider\" VARCHAR(50);\n\nCREATE INDEX \"idx_users_external_customer_id\" ON \"users\"(\"external_customer_id\");\nCREATE INDEX \"idx_users_subscription_status\" ON \"users\"(\"subscription_status\");\nCREATE INDEX \"idx_wallet_transactions_external_transaction_id\" ON \"wallet_transactions\"(\"external_transaction_id\");\n\n-- Comments for documentation\nCOMMENT ON TABLE \"payment_transactions\" IS 'Immutable audit log of all payment transactions for GDPR compliance and reconciliation';\nCOMMENT ON TABLE \"webhook_logs\" IS 'Webhook processing history with retry tracking and monitoring data';\nCOMMENT ON TABLE \"gdpr_consents\" IS 'User consent records for GDPR article 7 (proof of consent) compliance';\nCOMMENT ON TABLE \"disputes\" IS 'Payment disputes and chargeback records for dispute resolution';\n\nCOMMENT ON COLUMN \"payment_transactions\".\"schedule_delete_at\" IS 'Auto-delete after 90 days per GDPR data retention guidelines';\nCOMMENT ON COLUMN \"payment_transactions\".\"deleted_at\" IS 'Soft delete timestamp for audit trail; data is anonymized before deletion';\nCOMMENT ON COLUMN \"webhook_logs\".\"idempotency_key\" IS 'Unique key for idempotent webhook processing (provider-specific transaction ID)';\nCOMMENT ON COLUMN \"webhook_logs\".\"retry_until\" IS 'Scheduled time for next retry; NULL if no retry planned';\nCOMMENT ON COLUMN \"gdpr_consents\".\"version\" IS 'Consent version for compliance audits (e.g., \"1.0\", \"2.0\")';\n